#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_N 20000
#define MAX_M 40000
#define INF INT_MAX

// Define the structure for the graph
typedef struct Edge {
    int u, v, w;
} Edge;

// Define the structure for the disjoint set
typedef struct DisjointSet {
    int parent[MAX_N], rank[MAX_N];
} DisjointSet;

// Function to find the parent of a node in the disjoint set
int find(DisjointSet *ds, int node) {
    if (ds->parent[node] != node) {
        ds->parent[node] = find(ds, ds->parent[node]);
    }
    return ds->parent[node];
}

// Function to union two nodes in the disjoint set
void unionSet(DisjointSet *ds, int u, int v) {
    int rootU = find(ds, u);
    int rootV = find(ds, v);
    if (rootU != rootV) {
        if (ds->rank[rootU] < ds->rank[rootV]) {
            ds->parent[rootU] = rootV;
        } else if (ds->rank[rootU] > ds->rank[rootV]) {
            ds->parent[rootV] = rootU;
        } else {
            ds->parent[rootV] = rootU;
            ds->rank[rootU]++;
        }
    }
}

// Function to calculate the minimum spanning tree
void calculateMST(Edge edges[], int numEdges, int numVertices) {
    DisjointSet ds;
    for (int i = 0; i < numVertices; i++) {
        ds.parent[i] = i;
        ds.rank[i] = 0;
    }
    int numEdgesInMST = 0;
    long long totalWeight = 0;
    for (int i = 0; i < numEdges; i++) {
        int u = edges[i].u;
        int v = edges[i].v;
        int w = edges[i].w;
        if (find(&ds, u) != find(&ds, v)) {
            unionSet(&ds, u, v);
            numEdgesInMST++;
            totalWeight += w;
        }
    }
    if (numEdgesInMST == numVertices - 1) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        Edge edges[M];
        for (int i = 0; i < M; i++) {
            scanf("%d %d %d", &edges[i].u, &edges[i].v, &edges[i].w);
        }
        calculateMST(edges, M, N);
    }
    return 0;
}

